import json

def parse_token_response(body, requested_scope=None):
    data = json.loads(body)

    if 'error' in data:
        raise ValueError(data['error'])

    if 'access_token' not in data or 'token_type' not in data:
        raise ValueError('missing_required_field')

    result = dict(data)

    if 'expires_in' in result:
        result['expires_in'] = int(result['expires_in'])

    if 'scope' in result:
        if isinstance(result['scope'], str):
            result['scope'] = result['scope'].split()

    if requested_scope is not None and 'scope' in result:
        if isinstance(requested_scope, str):
            req_set = set(requested_scope.split())
        else:
            req_set = set(requested_scope)
        resp_set = set(result['scope'])
        if req_set != resp_set:
            raise Warning('scope_changed')

    return result

