try:
    parse_token_response('{"error": "invalid_grant"}')
    assert False, 'Expected ValueError'
except ValueError as e:
    assert str(e) == 'invalid_grant'

try:
    parse_token_response('{"error": "invalid_client"}')
    assert False, 'Expected ValueError'
except ValueError as e:
    assert str(e) == 'invalid_client'

try:
    parse_token_response('{"token_type": "Bearer"}')
    assert False, 'Expected ValueError'
except ValueError as e:
    assert str(e) == 'missing_required_field'

try:
    parse_token_response('{"access_token": "tok"}')
    assert False, 'Expected ValueError'
except ValueError as e:
    assert str(e) == 'missing_required_field'

try:
    parse_token_response('{"access_token": "tok", "token_type": "Bearer", "scope": "read"}', requested_scope='read write')
    assert False, 'Expected Warning'
except Warning as w:
    assert str(w) == 'scope_changed'

try:
    parse_token_response('{"access_token": "tok", "token_type": "Bearer", "scope": "read write"}', requested_scope=['read', 'write', 'admin'])
    assert False, 'Expected Warning'
except Warning as w:
    assert str(w) == 'scope_changed'
